#define DCREG_SH_LAYER8_DMA_MODE_Count                                         1
#define DCREG_SH_LAYER8_DMA_MODE_WriteMask                            0x0000007F
#define DCREG_SH_LAYER8_DMA_MODE_ResetValue                           0x00000010

/* Normal mode: read full image, don’t support ROI. One ROI mode: read one  **
** ROI region in one image. Two ROI mode: read two ROI regions in one image.  **
** Skip mode: skip the ROI region in one image. Extend layer mode: read       **
** image0 and image1, don’t support ROI. Extend layer ex mode: read ROI     **
** region from image0 and read exrended ROI region from image1.               */
#define DCREG_SH_LAYER8_DMA_MODE_VALUE                                       2:0
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_NORMAL                              0x0
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_ONE_ROI                             0x1
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_TWO_ROI                             0x2
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_SKIP                                0x3
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_EXTEND_LAYER                        0x4
#define   DCREG_SH_LAYER8_DMA_MODE_VALUE_EXTEND_LAYER_EX                     0x5

/* Exlayer and exlayer_ex support 2~4 img number. */
#define DCREG_SH_LAYER8_DMA_MODE_EX_NUM                                      6:3
#define   DCREG_SH_LAYER8_DMA_MODE_EX_NUM_NUM2                               0x2
#define   DCREG_SH_LAYER8_DMA_MODE_EX_NUM_NUM3                               0x3
#define   DCREG_SH_LAYER8_DMA_MODE_EX_NUM_NUM4                               0x4

/* Register dcregShLayer8DmaSramSize **
** ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~ */

/* Each layer needs some sram when this layer works.  This register is used   **
** to specify the dma sram size for this layer.                               */

#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_Address                           0x058290
#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_Count                                    1
#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_WriteMask                       0x0000FFFF
#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_ResetValue                      0x00000000

/* 64KBytes: Specify 64k bytes sram size. 128KBytes: Specify 128k bytes sram  **
** size. 192KBytes: Specify 192k bytes sram size. 256KBytes: Specify 256k     **
** bytes sram size. 320KBytes: Specify 320k bytes sram size. 384KBytes:       **
** Specify 384k bytes sram size.                                              */
#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE                                  7:0
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE64                       0x00
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE128                      0x01
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE192                      0x02
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE256                      0x03
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE320                      0x04
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_KBYTE384                      0x05

/* 32KBytes: Specify 32k bytes sram size. 64KBytes: Specify 64k bytes sram    **
** size. 96KBytes: Specify 96k bytes sram size. 128KBytes: Specify 128k bytes **
** sram size. 160KBytes: Specify 160k bytes sram size. 192KBytes: Specify     **
** 192k bytes sram size.                                                      */
#define DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_EX                              15:8
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_EX_KBYTE32                    0x00
#define   DCREG_SH_LAYER8_DMA_SRAM_SIZE_VALUE_EX_KBYTE64                    0x01
