/* Register dcregLayer14Config **
** ~~~~~~~~~~~~~~~~~~~~~~~~~~~ */

/* Layer14 Configuration Register.  Layer14 attributes control.  This         **
** register is not buffered.                                                  */

#define DCREG_LAYER14_CONFIG_Address                                    0x070000
#define DCREG_LAYER14_CONFIG_Count                                             1
#define DCREG_LAYER14_CONFIG_WriteMask                                0x0000000F
#define DCREG_LAYER14_CONFIG_ResetValue                               0x00000000

/* This field indicates register switch status.  OK means HW can copy the     **
** register from shadow side to active side at the beginning of the frame.    **
** Wait means HW cannot copy the register from shadow side to active side at  **
** the beginning of the frame.  This register programming is not done by SW.  **
**  We call the registers configured by SW directly shadow registers.  We     **
** call the registers used by HW active registers.                            */
#define DCREG_LAYER14_CONFIG_REG_SWITCH                                      0:0
#define   DCREG_LAYER14_CONFIG_REG_SWITCH_WAIT                               0x0
#define   DCREG_LAYER14_CONFIG_REG_SWITCH_OK                                 0x1

/* Reset Layer14 Registers to default value. This bit is WRITE ONLY.  */
#define DCREG_LAYER14_CONFIG_RESET                                           1:1
#define   DCREG_LAYER14_CONFIG_RESET_RESET                                   0x1

/* Force HW copy the shadow register to active register directly.  */
#define DCREG_LAYER14_CONFIG_FORCE_FLIP                                      2:2

/* AxiBurstLenSel.  */
#define DCREG_LAYER14_CONFIG_AXI_BURST_LEN_SEL                               3:3
#define   DCREG_LAYER14_CONFIG_AXI_BURST_LEN_SEL_BURST8                      0x0
#define   DCREG_LAYER14_CONFIG_AXI_BURST_LEN_SEL_BURST4                      0x1

